38	    >
39	      {d.split("|").map((path, i) => (
40	        <path key={i} d={path} />
41	      ))}
42	    </svg>
43	  );
44	}
45	
46	const PIPELINE: StageNode[] = [
47	  {
48	    key: "normalize",
49	    label: "normalize",
50	    hint: "Convert raw input → markdown",
51	    icon: (cls) =>
52	      <Icon cls={cls} d="M7 4h10v16H7z|M9 8h6|M9 12h6|M9 16h4" />,
53	  },
