59	      <Icon cls={cls} d="M3 7l9-4 9 4-9 4-9-4z|M3 12l9 4 9-4|M3 17l9 4 9-4" />,
60	  },
61	  {
62	    key: "resolve",
63	    label: "resolve",
64	    hint: "Link entities from stammdaten",
65	    icon: (cls) =>
66	      <Icon cls={cls} d="M10 14a4 4 0 010-5.66l3-3a4 4 0 015.66 5.66l-1.5 1.5|M14 10a4 4 0 010 5.66l-3 3a4 4 0 01-5.66-5.66l1.5-1.5" />,
67	  },
68	  {
69	    key: "locate",
70	    label: "locate",
71	    hint: "Vector search wiki sections",
72	    icon: (cls) =>
73	      <Icon cls={cls} d="M12 2v3|M12 19v3|M2 12h3|M19 12h3|M12 7a5 5 0 100 10 5 5 0 000-10z|M12 12h.01" />,
74	  },
75	  {
76	    key: "extract",
77	    label: "extract",
78	    hint: "LLM → patch plan ops",
79	    icon: (cls) =>
80	      <Icon cls={cls} d="M4 4l8 8|M4 20l8-8|M14 7l6 5-6 5|M14 7v10" />,
81	  },
82	  {
83	    key: "patch",
84	    label: "patch",
85	    hint: "Apply ops to wiki files",
86	    icon: (cls) =>
87	      <Icon cls={cls} d="M12 20h9|M16.5 3.5a2.12 2.12 0 113 3L7 19l-4 1 1-4 12.5-12.5z" />,
88	  },
