105	type StageRecord = {
106	  state: StageState;
107	  data: Record<string, unknown> | null;
108	  startedAt: number | null;
109	  endedAt: number | null;
110	};
111	
112	function emptyStages(): Record<string, StageRecord> {
113	  const out: Record<string, StageRecord> = {};
114	  for (const n of PIPELINE) {
115	    out[n.key] = { state: "pending", data: null, startedAt: null, endedAt: null };
116	  }
117	  return out;
118	}
119	
120	const KIND_LABELS: Record<Kind, string> = {
121	  email: "Emails",
122	  invoice: "Invoices",
123	  bank: "Bank tx",
124	};
125	
126	export function IngestPage() {
127	  const [days, setDays] = useState<SimDay[] | null>(null);
128	  const [error, setError] = useState<string | null>(null);
129	  const [day, setDay] = useState<number | null>(null);
130	  const [kind, setKind] = useState<Kind>("email");
131	  const [itemId, setItemId] = useState<string | null>(null);
132	  const [mode, setMode] = useState<Mode>("isolated");
133	  const [running, setRunning] = useState(false);
134	  const [result, setResult] = useState<SimIngestResponse | null>(null);
135	  const [activeFile, setActiveFile] = useState<string | null>(null);
136	  const [events, setEvents] = useState<SimStageEvent[]>([]);
137	  const [cursor, setCursor] = useState<number>(-1);
138	  const [followLive, setFollowLive] = useState(true);
139	
140	  useEffect(() => {
141	    fetchIncremental()
142	      .then((d) => {
143	        setDays(d);
144	        if (d.length > 0) setDay(d[d.length - 1].day);
145	      })
146	      .catch((e) => setError(String(e)));
147	  }, []);
148	
149	  const currentDay = useMemo(
150	    () => days?.find((d) => d.day === day) ?? null,
151	    [days, day],
152	  );
153	
154	  const items: SimItem[] = useMemo(() => {
155	    if (!currentDay) return [];
156	    if (kind === "email") return currentDay.emails;
157	    if (kind === "invoice") return currentDay.invoices;
158	    return currentDay.bank;
159	  }, [currentDay, kind]);
160	
161	  useEffect(() => {
162	    if (items.length === 0) {
163	      setItemId(null);
164	      return;
165	    }
166	    if (!itemId || !items.some((i) => i.id === itemId)) {
167	      setItemId(items[0].id);
168	    }
169	  }, [items, itemId]);
170	
171	  useEffect(() => {
172	    if (!result) {
173	      setActiveFile(null);
174	      return;
175	    }
176	    setActiveFile(result.files[0]?.path ?? null);
177	  }, [result]);
178	
179	  function handleStage(ev: SimStageEvent) {
180	    setEvents((prev) => {
181	      const enriched: SimStageEvent = {
182	        ...ev,
183	        data: { ...ev.data, _recvAt: performance.now() },
184	      };
185	      const next = [...prev, enriched];
186	      if (followLive) setCursor(next.length - 1);
187	      return next;
188	    });
189	  }
190	
191	  async function handleRun() {
192	    if (!day || !itemId) return;
193	    setRunning(true);
194	    setError(null);
195	    setResult(null);
196	    setEvents([]);
197	    setCursor(-1);
198	    setFollowLive(true);
199	    try {
200	      await runSimIngestStream(
201	        { day, kind, id: itemId, mode },
202	        {
203	          onStage: handleStage,
204	          onResponse: (resp) => setResult(resp),
205	          onError: (err) => setError(`${err.status}: ${err.detail}`),
206	        },
207	      );
208	    } catch (e) {
209	      setError(String(e));
210	    } finally {
