525	type DerivedView = {
526	  stages: Record<string, StageRecord>;
527	  activeStage: string | null;
528	  terminalStatus: "applied" | "no_signal" | null;
529	  currentEvent: SimStageEvent | null;
530	};
531	
532	function deriveFromEvents(events: SimStageEvent[], upto: number): DerivedView {
533	  const stages = emptyStages();
534	  let activeStage: string | null = null;
535	  let terminalStatus: "applied" | "no_signal" | null = null;
536	  const slice = upto < 0 ? [] : events.slice(0, upto + 1);
537	  for (const ev of slice) {
538	    const raw = ev.stage;
539	    if (raw === "done") {
540	      terminalStatus = (ev.data?.status as "applied" | "no_signal") ?? null;
541	      activeStage = null;
542	      if (terminalStatus === "no_signal") {
543	        for (const n of PIPELINE) {
544	          if (
545	            n.key !== "normalize" &&
546	            n.key !== "classify" &&
547	            stages[n.key].state === "pending"
548	          ) {
549	            stages[n.key] = { ...stages[n.key], state: "skipped" };
550	          }
551	        }
552	      }
553	      continue;
554	    }
555	    const isDone = raw.endsWith(".done");
556	    const key = isDone ? raw.slice(0, -5) : raw;
557	    if (!PIPELINE.some((n) => n.key === key)) continue;
558	    const cur = stages[key];
559	    const { _recvAt, ...visibleData } = ev.data as Record<string, unknown>;
560	    const ts = typeof _recvAt === "number" ? _recvAt : null;
561	    if (isDone) {
562	      stages[key] = {
563	        ...cur,
564	        state: "done",
565	        data: visibleData,
566	        endedAt: ts,
567	      };
568	      if (activeStage === key) activeStage = null;
569	    } else {
570	      stages[key] = {
571	        ...cur,
572	        state: "active",
573	        startedAt: ts,
574	      };
575	      activeStage = key;
576	    }
577	  }
578	  const currentEvent = upto >= 0 && upto < events.length ? events[upto] : null;
579	  return { stages, activeStage, terminalStatus, currentEvent };
580	}
581	
582	function PipelineView({
583	  events,
584	  cursor,
585	  followLive,
586	  running,
587	  onCursor,
588	  onFollowLive,
589	}: {
590	  events: SimStageEvent[];
591	  cursor: number;
592	  followLive: boolean;
593	  running: boolean;
594	  onCursor: (idx: number) => void;
595	  onFollowLive: () => void;
596	}) {
597	  const { stages, activeStage, terminalStatus, currentEvent } = useMemo(
598	    () => deriveFromEvents(events, cursor),
599	    [events, cursor],
600	  );
601	  const total = events.length;
602	  const idx = cursor < 0 ? 0 : cursor + 1;
603	  return (
604	    <div className="flex min-h-0 flex-1 flex-col">
605	      <div className="border-b border-[var(--color-border)] px-4 py-3">
606	        <div className="mb-2 flex items-center justify-between">
607	          <div className="flex items-center gap-2">
608	            <span className="font-mono text-[11px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
609	              Pipeline
610	            </span>
611	            {currentEvent && (
612	              <span className="font-mono text-[11px] text-[var(--color-fg-muted)]">
613	                · {currentEvent.stage}
614	              </span>
615	            )}
616	          </div>
617	          <span
618	            className={cn(
619	              "font-mono text-[11px] uppercase tracking-[0.18em]",
620	              terminalStatus === "applied" && "text-[var(--color-accent)]",
621	              terminalStatus === "no_signal" &&
622	                "text-[var(--color-fg-muted)]",
623	              !terminalStatus && running && "text-[var(--color-accent)]",
624	            )}
625	          >
626	            {terminalStatus
627	              ? terminalStatus.replace("_", " ")
628	              : running
629	                ? "running"
630	                : "idle"}
631	          </span>
632	        </div>
633	        <div className="flex flex-wrap items-stretch gap-1">
634	          {PIPELINE.map((node, i) => {
635	            const rec = stages[node.key];
636	            return (
637	              <div key={node.key} className="flex items-stretch">
638	                <StageChip
639	                  node={node}
640	                  state={rec.state}
641	                  active={activeStage === node.key}
642	                  data={rec.data}
643	                  duration={
644	                    rec.startedAt && rec.endedAt
645	                      ? rec.endedAt - rec.startedAt
646	                      : null
647	                  }
648	                  onClick={() => {
649	                    const target = lastEventIndexFor(events, node.key);
650	                    if (target >= 0) onCursor(target);
651	                  }}
652	                />
653	                {i < PIPELINE.length - 1 && <Connector />}
654	              </div>
655	            );
656	          })}
657	        </div>
658	        <div className="mt-3 flex items-center gap-2">
659	          <button
660	            onClick={() => onCursor(Math.max(0, cursor - 1))}
661	            disabled={cursor <= 0}
662	            className="rounded border border-[var(--color-border-2)] bg-[var(--color-bg)] px-2 py-1 font-mono text-[11px] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)] disabled:opacity-30"
663	            title="prev event"
664	          >
665	            ◀ prev
666	          </button>
667	          <input
668	            type="range"
669	            min={0}
670	            max={Math.max(0, total - 1)}
671	            value={cursor < 0 ? 0 : cursor}
672	            disabled={total === 0}
673	            onChange={(e) => onCursor(Number(e.target.value))}
674	            className="flex-1 accent-[var(--color-accent)]"
675	          />
676	          <button
677	            onClick={() => onCursor(Math.min(total - 1, cursor + 1))}
678	            disabled={cursor >= total - 1 || total === 0}
679	            className="rounded border border-[var(--color-border-2)] bg-[var(--color-bg)] px-2 py-1 font-mono text-[11px] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)] disabled:opacity-30"
680	            title="next event"
681	          >
682	            next ▶
683	          </button>
684	          <button
685	            onClick={onFollowLive}
686	            disabled={followLive || total === 0}
687	            className={cn(
688	              "rounded border px-2 py-1 font-mono text-[11px] uppercase tracking-wide transition-colors",
689	              followLive
690	                ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
691	                : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)]",
692	            )}
693	            title="snap to latest event"
694	          >
695	            live
696	          </button>
697	          <span className="ml-1 font-mono text-[11px] text-[var(--color-fg-muted)]">
698	            {idx} / {total}
699	          </span>
700	        </div>
701	        {currentEvent && (
702	          <div className="mt-2 font-mono text-[11px] text-[var(--color-fg-muted)]">
703	            {hintFor(currentEvent.stage)}
704	          </div>
705	        )}
706	      </div>
707	      <div className="grid grid-cols-2 gap-3 overflow-auto px-4 py-3">
708	        {PIPELINE.filter((n) => stages[n.key].data || stages[n.key].state === "active").map(
709	          (n) => (
710	            <StagePanel key={n.key} node={n} record={stages[n.key]} />
711	          ),
712	        )}
713	        {Object.values(stages).every(
714	          (s) => s.state === "pending" || s.state === "active",
715	        ) &&
716	          running && (
717	            <div className="col-span-2 text-[12.5px] text-[var(--color-fg-muted)]">
718	              waiting for first stage…
719	            </div>
720	          )}
721	      </div>
722	    </div>
723	  );
724	}
725	
726	function lastEventIndexFor(events: SimStageEvent[], key: string): number {
727	  for (let i = events.length - 1; i >= 0; i--) {
728	    const raw = events[i].stage;
729	    const k = raw.endsWith(".done") ? raw.slice(0, -5) : raw;
730	    if (k === key) return i;
731	  }
732	  return -1;
733	}
734	
735	function hintFor(stage: string): string {
736	  if (stage === "done") return "Pipeline finished.";
737	  const isDone = stage.endsWith(".done");
738	  const key = isDone ? stage.slice(0, -5) : stage;
739	  const node = PIPELINE.find((n) => n.key === key);
740	  if (!node) return stage;
741	  return isDone ? `${node.label} → done. ${node.hint}` : `${node.label} → ${node.hint}`;
742	}
743	
744	function StageChip({
745	  node,
746	  state,
747	  active,
748	  data,
749	  duration,
750	  onClick,
751	}: {
752	  node: StageNode;
753	  state: StageState;
754	  active: boolean;
755	  data: Record<string, unknown> | null;
756	  duration: number | null;
757	  onClick: () => void;
758	}) {
759	  const bgClass =
760	    state === "done"
761	      ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
762	      : state === "active" || active
763	        ? "border-[var(--color-accent)] bg-[var(--color-accent)]/15 text-[var(--color-accent)] animate-pulse"
764	        : state === "error"
765	          ? "border-red-500/50 bg-red-500/10 text-red-400"
766	          : state === "skipped"
767	            ? "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-dim)] opacity-60"
768	            : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)]";
769	  const indicator =
770	    state === "done"
771	      ? "✓"
772	      : state === "active" || active
773	        ? "●"
774	        : state === "error"
775	          ? "✕"
776	          : state === "skipped"
777	            ? "—"
778	            : "○";
779	  const summary = chipSummary(node.label, data);
780	  return (
781	    <button
782	      type="button"
783	      onClick={onClick}
784	      className={cn(
785	        "flex min-w-[120px] flex-col rounded-md border px-2 py-1.5 text-left font-mono text-[11px] transition-colors hover:brightness-110",
786	        bgClass,
787	      )}
788	      title={`${node.hint}${data ? `\n\n${JSON.stringify(data, null, 2)}` : ""}`}
789	    >
790	      <div className="flex items-center gap-1.5">
791	        <span className="text-[10px]">{indicator}</span>
792	        {node.icon()}
793	        <span className="font-medium uppercase tracking-wide">{node.label}</span>
794	      </div>
795	      {summary && (
796	        <span className="mt-0.5 truncate text-[10.5px] opacity-80">
797	          {summary}
798	        </span>
799	      )}
800	      {duration !== null && (
801	        <span className="text-[9.5px] opacity-60">{Math.round(duration)}ms</span>
802	      )}
803	    </button>
804	  );
805	}
806	
807	function Connector() {
808	  return (
809	    <div className="flex items-center px-0.5 text-[var(--color-border-2)]">
810	      <span className="font-mono text-[12px]">→</span>
811	    </div>
812	  );
813	}
814	
815	function chipSummary(
816	  label: string,
817	  data: Record<string, unknown> | null,
818	): string | null {
819	  if (!data) return null;
820	  if (label === "classify") {
821	    const cat = data.category as string | undefined;
822	    const conf = data.confidence as number | undefined;
823	    if (cat) return `${cat} ${conf != null ? `· ${conf}` : ""}`.trim();
824	  }
825	  if (label === "extract") {
826	    const ops = data.ops as number | undefined;
827	    if (typeof ops === "number") return `${ops} ops`;
828	  }
829	  if (label === "patch") {
830	    const ops = data.applied_ops as number | undefined;
831	    if (typeof ops === "number") return `${ops} writes`;
832	  }
833	  if (label === "resolve") {
834	    const ids = data.entity_ids as string[] | undefined;
835	    if (ids && ids.length) return ids.slice(0, 2).join(", ");
836	  }
837	  if (label === "locate") {
838	    const sec = data.sections as string[] | undefined;
839	    if (sec && sec.length) return `${sec.length} sections`;
840	  }
841	  if (label === "normalize") {
842	    const chars = data.chars as number | undefined;
843	    if (typeof chars === "number") return `${chars} chars`;
844	  }
845	  if (label === "reindex") {
846	    const c = data.count as number | undefined;
847	    if (typeof c === "number") return `${c} files`;
848	  }
849	  return null;
850	}
851	
852	function StagePanel({
853	  node,
854	  record,
855	}: {
856	  node: StageNode;
857	  record: StageRecord;
858	}) {
859	  if (!record.data && record.state !== "active") return null;
860	  return (
861	    <div className="rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)]/40 p-2">
862	      <div className="mb-1 flex items-center justify-between font-mono text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-dim)]">
863	        <span className="flex items-center gap-1.5">
864	          {node.icon()}
865	          {node.label}
866	        </span>
867	        <span
868	          className={cn(
869	            record.state === "done" && "text-[var(--color-accent)]",
870	            record.state === "active" && "text-[var(--color-accent)]",
871	          )}
872	        >
873	          {record.state}
874	        </span>
875	      </div>
876	      {record.data ? (
877	        <pre className="max-h-[220px] overflow-auto whitespace-pre-wrap break-all font-mono text-[11px] leading-snug text-[var(--color-fg-muted)]">
878	          {JSON.stringify(record.data, null, 2)}
879	        </pre>
880	      ) : (
881	        <div className="font-mono text-[11px] text-[var(--color-fg-muted)]">
882	          working…
883	        </div>
884	      )}
885	    </div>
886	  );
887	}
