  color: var(--color-fg);
  font-family: var(--font-sans);
  font-size: 14px;
  border-bottom: 1px solid var(--color-border);
}
[cmdk-list] {
  max-height: 360px;
  overflow: auto;
  padding: 6px;
}
[cmdk-item] {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 6px;
