  background: var(--color-surface-2);
  padding: 0.1em 0.4em;
  border-radius: 4px;
  border: 1px solid var(--color-border);
  font-size: 0.82em;
}

.prose-wiki pre {
  border: 1px solid var(--color-border);
  border-radius: 8px;
  padding: 1em 1.1em;
  background: var(--color-surface);
