}

/* light mode overrides */
.light .prose-wiki {
  --tw-prose-body: #2a2a26;
  --tw-prose-headings: #0e0e0c;
  --tw-prose-bold: #0e0e0c;
}

/* cmdk styles */
[cmdk-root] {
  background: var(--color-surface);
  border: 1px solid var(--color-border-2);
  border-radius: 12px;
  overflow: hidden;
  box-shadow:
    0 30px 80px -20px rgba(0, 0, 0, 0.7),
    0 0 0 1px rgba(212, 255, 60, 0.06);
}
[cmdk-input] {
  width: 100%;
  background: transparent;
  border: 0;
  outline: 0;
  padding: 14px 18px;
  color: var(--color-fg);
  font-family: var(--font-sans);
  font-size: 14px;
  border-bottom: 1px solid var(--color-border);
}
[cmdk-list] {
  max-height: 360px;
  overflow: auto;
  padding: 6px;
}
[cmdk-item] {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 6px;
  color: var(--color-fg);
  cursor: pointer;
  font-size: 13px;
  font-family: var(--font-mono);
}
[cmdk-item][data-selected="true"] {
  background: var(--color-surface-2);
  color: var(--color-accent);
}
[cmdk-empty] {
  padding: 28px;
  text-align: center;
  color: var(--color-fg-muted);
  font-size: 13px;
}

/* Resizable handle (react-resizable-panels v4 emits [data-separator]) */
[data-group][data-testid] > [role="separator"] {
  position: relative;
  background: var(--color-border);
  transition: background 0.15s;
}
[data-group] > [role="separator"][aria-orientation="vertical"] {
  width: 1px;
  cursor: col-resize;
}
[data-group] > [role="separator"][aria-orientation="horizontal"] {
  height: 1px;
  cursor: row-resize;
}
[data-group] > [role="separator"]:hover,
[data-group] > [role="separator"][data-separator="active"],
[data-group] > [role="separator"][data-separator="focus"] {
  background: var(--color-accent);
}
[data-group] > [role="separator"]::after {
  content: "";
  position: absolute;
  inset: -3px;
}

/* tree row animation */
@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(2px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.fade-up {
  animation: fade-up 0.18s ease-out both;
}

/* hide-on-mobile utility — applied by App.tsx via JS-driven media query */
.is-mobile-hidden {
  display: none !important;
}

